import java.util.concurrent.Callable;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.TimeoutException;

/**
 * 文件服务类，提供基于bash的文件模式查找功能。
 *
 * 主要特点：
 * - 使用 Runtime.exec 调用 bash -c 执行 find 命令
 * - 使用 -type f 仅查找文件
 * - 使用 -name 进行模式匹配（支持通配符，如 *.txt）
 * - 使用 head -n 10 限制最多返回 10 条结果
 * - 对用户输入进行 Shell 安全引用，避免命令注入
 * - 读取命令输出（stdout）并在失败时返回错误信息（stderr）
 */
public class FileService {

    /**
     * 根据给定目录和文件模式查找文件（最多返回10个结果）。
     *
     * @param searchDir   搜索目录路径
     * @param filePattern 文件名模式（如 "*.txt", "*.java", "passwd"）
     * @return 查找到的文件列表（每行一个文件路径），或错误信息（以 "Error: " 开头）
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        // 基本参数校验
        if (searchDir == null || searchDir.trim().isEmpty()) {
            return "Error: searchDir must not be null or empty.";
        }
        if (filePattern == null || filePattern.trim().isEmpty()) {
            return "Error: filePattern must not be null or empty.";
        }

        // 对用户输入进行 Shell 安全引用，防止命令注入
        String qDir = shellQuote(searchDir.trim());
        String qPattern = shellQuote(filePattern.trim());

        // 使用 find + head 限制输出数量。-type f 仅文件，-name 进行模式匹配。
        // 使用 bash -c 执行管道命令。
        String command = "find " + qDir + " -type f -name " + qPattern + " -print | head -n 10";
        String[] cmd = {"bash", "-c", command};

        Process process = null;
        ExecutorService pool = Executors.newFixedThreadPool(2);
        try {
            process = Runtime.getRuntime().exec(cmd);

            // 不会向进程写入任何数据，立即关闭其标准输入
            try {
                process.getOutputStream().close();
            } catch (IOException ignored) {
            }

            // 并发读取 stdout 和 stderr，避免阻塞
            Future<String> stdoutFuture = pool.submit(streamReader(process.getInputStream()));
            Future<String> stderrFuture = pool.submit(streamReader(process.getErrorStream()));

            // 等待进程结束，设置一个合理的超时（例如 15 秒）
            boolean finished = process.waitFor(15, TimeUnit.SECONDS);
            if (!finished) {
                process.destroyForcibly();
                // 等待强制销毁完成
                process.waitFor(5, TimeUnit.SECONDS);
                return "Error: search command timed out.";
            }

            int exitCode = process.exitValue();

            // 获取输出
            String stdout = getFutureSilently(stdoutFuture, 5);
            String stderr = getFutureSilently(stderrFuture, 5);

            if (exitCode != 0) {
                // 命令失败时返回错误信息
                String err = (stderr == null ? "" : stderr.trim());
                if (err.isEmpty()) {
                    err = "Failed to execute search command (exit code " + exitCode + ").";
                }
                return "Error: " + err;
            }

            // 成功时返回标准输出，去除末尾多余空白但保留行结构
            if (stdout == null) {
                return "";
            }
            return rstrip(stdout);
        } catch (IOException e) {
            return "Error: I/O exception while executing command: " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: command execution was interrupted.";
        } finally {
            // 关闭线程池
            pool.shutdownNow();
            // 确保进程被清理
            if (process != null) {
                try {
                    process.getInputStream().close();
                } catch (IOException ignored) {
                }
                try {
                    process.getErrorStream().close();
                } catch (IOException ignored) {
                }
                try {
                    process.getOutputStream().close();
                } catch (IOException ignored) {
                }
            }
        }
    }

    /**
     * 将任意字符串安全地用单引号包裹用于 Bash，避免命令注入。
     * 规则：用单引号包裹，并将内部的单引号替换为 '\''（即 ' + " + ' + " + ' 序列）
     */
    private static String shellQuote(String s) {
        // 将 ' 替换为 '\''（结束单引号，插入转义的单引号，再开始单引号）
        return "'" + s.replace("'", "'\"'\"'") + "'";
    }

    /**
     * 创建一个可调用任务，读取输入流的全部内容为字符串（UTF-8）。
     */
    private static Callable<String> streamReader(InputStream in) {
        return () -> {
            StringBuilder sb = new StringBuilder();
            try (BufferedReader br = new BufferedReader(new InputStreamReader(in, StandardCharsets.UTF_8))) {
                String line;
                boolean first = true;
                while ((line = br.readLine()) != null) {
                    if (!first) {
                        sb.append('\n');
                    } else {
                        first = false;
                    }
                    sb.append(line);
                }
            }
            return sb.toString();
        };
    }

    /**
     * 尝试在限定时间内从 Future 获取结果，若发生异常则返回空字符串。
     */
    private static String getFutureSilently(Future<String> future, int seconds) {
        try {
            return future.get(seconds, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "";
        } catch (ExecutionException | TimeoutException e) {
            return "";
        }
    }

    /**
     * 去除字符串末尾的空白字符（不改变中间的换行结构）。
     */
    private static String rstrip(String s) {
        int end = s.length();
        while (end > 0 && Character.isWhitespace(s.charAt(end - 1))) {
            end--;
        }
        return s.substring(0, end);
    }
}

